hooks.onDraw:
const s = world.state;
for (const e of world.entities) { if (e.type === 'learner') world.draw.learner(e); }
const UI = 'ui-sans-serif, system-ui, sans-serif';
const t = world.t;
if ((s.chartA || 0) > 0.01) {
  ctx.save();
  ctx.globalAlpha = s.chartA;
  world.draw.rrect(424, 32, 348, 226, 12);
  ctx.fillStyle = 'rgba(9,12,27,0.62)';
  ctx.fill();
  world.draw.rrect(424, 32, 348, 226, 12);
  ctx.strokeStyle = 'rgba(110,120,150,0.30)';
  ctx.lineWidth = 1;
  ctx.stroke();
  if ((s.glow || 0) > 0.01) {
    const g = ctx.createRadialGradient(600, 145, 10, 600, 145, 190);
    g.addColorStop(0, 'rgba(244,172,29,' + (0.32 * s.glow).toFixed(3) + ')');
    g.addColorStop(1, 'rgba(244,172,29,0)');
    ctx.fillStyle = g;
    ctx.fillRect(400, 10, 400, 290);
  }
  const f = world.draw.axes(450, 60, 300, 170, { xDomain: [2006, 2010], yDomain: [0, 12], xTicks: [2006, 2007, 2008, 2009, 2010], yTicks: [0, 5, 10], xFormat: function (v) { return String(Math.round(v)); }, yFormat: function (v) { return v + '%'; }, yLabel: 'mejora sobre cinematch', color: 'rgba(232,226,210,0.45)', labelColor: '#9aa3bd' });
  world.draw.plot(f, [[2006, 10], [2010, 10]], { color: '#c44a3e', dash: [5, 4], width: 1.5 });
  ctx.fillStyle = '#c44a3e'; ctx.font = '600 10px ' + UI; ctx.textAlign = 'left'; ctx.textBaseline = 'alphabetic';
  ctx.fillText('meta: 10%', 458, 102);
  world.draw.plot(f, s.curve, { color: '#5b8def', width: 2.5, reveal: s.reveal || 0, fill: 'rgba(91,141,239,0.10)' });
  if ((s.glow || 0) > 0.05) {
    world.draw.plot(f, s.sprint, { color: '#F4AC1D', width: 3, reveal: s.glow });
  }
  if ((s.glow || 0) > 0.9) {
    const px = 450 + 300 * ((2009.55 - 2006) / 4);
    const py = 60 + 170 * (1 - 10.09 / 12);
    ctx.fillStyle = '#F4AC1D';
    ctx.beginPath(); ctx.arc(px, py, 4 + Math.sin(t * 6) * 1.6, 0, Math.PI * 2); ctx.fill();
  }
  ctx.restore();
}
if ((s.barsA || 0) > 0.01) {
  ctx.save();
  ctx.globalAlpha = s.barsA;
  const fb = world.draw.axes(80, 84, 250, 146, { xDomain: [0, 1], yDomain: [0, 12], xTicks: [], yTicks: [0, 10], yFormat: function (v) { return v + '%'; }, color: 'rgba(232,226,210,0.35)', labelColor: '#9aa3bd' });
  world.draw.bars(fb, s.modelos, { gap: 0.32, reveal: s.barsR || 0, labels: true, labelColor: '#9aa3bd', color: '#5b8def' });
  ctx.fillStyle = '#d4dbeb'; ctx.font = '600 11px ' + UI; ctx.textAlign = 'left';
  ctx.fillText('MODELOS POR SEPARADO VS ENSAMBLE', 80, 72);
  ctx.restore();
}
const logoA = Math.max(0, 1 - Math.max((s.legacy || 0) * 3, (s.barsA || 0) * 2));
if (logoA > 0.01) {
  ctx.save();
  ctx.globalAlpha = logoA;
  world.draw.rrect(84, 54, 44, 44, 10);
  ctx.fillStyle = '#c44a3e';
  ctx.fill();
  world.draw.rrect(84, 54, 44, 44, 10);
  ctx.strokeStyle = 'rgba(251,250,246,0.25)';
  ctx.lineWidth = 1.5;
  ctx.stroke();
  ctx.fillStyle = '#FBFAF6';
  ctx.font = '700 26px Fraunces, Georgia, serif';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText('N', 106, 77);
  ctx.fillStyle = '#9aa3bd';
  ctx.font = '600 9px ' + UI;
  ctx.textBaseline = 'alphabetic';
  ctx.fillText('N E T F L I X', 106, 112);
  ctx.restore();
}
if ((s.legacy || 0) > 0.01) {
  ctx.save();
  const a1 = Math.max(0, Math.min(1, s.legacy * 3));
  const a2 = Math.max(0, Math.min(1, s.legacy * 3 - 1));
  const a3 = Math.max(0, Math.min(1, s.legacy * 3 - 2));
  ctx.globalAlpha = a1;
  const n1 = world.draw.node(90, 64, 200, 40, { label: 'datos públicos', fill: '#F6F2E8', labelColor: '#1F2547' });
  ctx.globalAlpha = a2;
  const n2 = world.draw.node(90, 124, 200, 40, { label: 'evaluación reproducible', fill: '#F6F2E8', labelColor: '#1F2547' });
  ctx.globalAlpha = a3;
  const n3 = world.draw.node(90, 184, 200, 40, { label: 'ensambles', fill: '#F6F2E8', labelColor: '#1F2547' });
  if (a3 > 0.05) {
    ctx.globalAlpha = a3;
    const n4 = world.draw.node(430, 118, 250, 52, { label: 'aprendizaje automático moderno', fill: '#1F2547', labelColor: '#FBFAF6', stroke: '#F4AC1D' });
    world.draw.connector(n1.right, n4.left, { color: '#F4AC1D', curve: 18 });
    world.draw.connector(n2.right, n4.left, { color: '#F4AC1D' });
    world.draw.connector(n3.right, n4.left, { color: '#F4AC1D', curve: -18 });
  }
  ctx.restore();
}
